 1	import { type FC, useState } from 'react';
 2	import HelpSubTopic from 'src/onlineHelp/learningExperience/HelpSubTopic';
 3	import {
 4	  type LearningExperienceSubTopic,
 5	  ListStyleType,
 6	} from 'src/onlineHelp/learningExperience/types';
 7	import {
 8	  getClassForListStyle,
 9	  getTextListComponentForListStyle,
10	} from 'src/onlineHelp/learningExperience/utils';
11	
12	import {
13	  ExpandableSection,
14	  Text,
15	  TextContent,
16	  TextList,
17	  TextListItem,
18	} from '@patternfly/react-core';
19	import { css } from '@patternfly/react-styles';
20	import { isEmpty } from '@utils/helpers';
21	
22	type HelpTopicSectionProps = {
23	  topic: LearningExperienceSubTopic;
24	  index: number;
25	  listStyleType?: ListStyleType;
26	};
27	
28	const HelpTopicSection: FC<HelpTopicSectionProps> = ({ index, listStyleType, topic }) => {
29	  const [isExpanded, setIsExpanded] = useState<boolean>(false);
30	  const prefix = listStyleType === ListStyleType.DECIMAL ? `${index + 1}.` : null;
31	
32	  const renderTopicTitle = () => {
33	    const title = (
34	      <TextContent>
35	        <Text component="p">
36	          {listStyleType === ListStyleType.DECIMAL ? (
37	            <>
38	              {prefix} {topic.title}
39	            </>
40	          ) : (
41	            topic.title
42	          )}
43	        </Text>
44	      </TextContent>
45	    );
46	
47	    if (isEmpty(listStyleType) || listStyleType === ListStyleType.DECIMAL) {
48	      return title;
49	    }
50	
51	    return (
52	      <div className={getClassForListStyle(listStyleType)}>
53	        <TextList component={listStyleType === ListStyleType.LOWER_ALPHA ? 'ol' : 'ul'}>
54	          <TextListItem>{title}</TextListItem>
55	        </TextList>
56	      </div>
57	    );
58	  };
59	
60	  return (
61	    <ExpandableSection
62	      className={css(
63	        'forklift--learning__help-section',
64	        isEmpty(topic.subTopics) && 'm-non-expandable',
65	        topic.subListStyleType === ListStyleType.DESCRIPTIONS && 'm-has-descriptions',
66	      )}
67	      toggleContent={<div className="pf-v6-u-ml-sm">{renderTopicTitle()}</div>}
68	      isExpanded={isExpanded}
69	      onToggle={(_ev, expanded) => {
70	        if (topic.subTopics) {
71	          setIsExpanded(expanded);
72	        }
73	      }}
74	    >
75	      {topic.subTopics ? (
76	        <div className="pf-v6-u-ml-lg pf-v6-u-mb-md">
77	          <div
78	            id={`${topic.id}: ${topic.subListStyleType}`}
79	            className={getClassForListStyle(topic.subListStyleType)}
80	          >
81	            {topic.subListStyleType === ListStyleType.DESCRIPTIONS ? (
82	              topic.subTopics.map((subTopic) => (
83	                <HelpSubTopic key={subTopic.id} topic={subTopic} noListItem />
84	              ))
85	            ) : (
86	              <TextList component={getTextListComponentForListStyle(topic.subListStyleType)}>
87	                {topic.subTopics.map((subTopic) => (
88	                  <HelpSubTopic key={subTopic.id} topic={subTopic} />
89	                ))}
90	              </TextList>
91	            )}
92	          </div>
93	        </div>
94	      ) : null}
95	    </ExpandableSection>
96	  );
97	};
98	
99	export default HelpTopicSection;

